import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import Cookies from "js-cookie";
import { useState, useEffect } from "react";
import axios from "axios";

import PermissionContext from "./context/PermissionContext";
import ProtectedRoute from "./components/ProtectedRoute";

import AdminLogin from "./pages/AdminLogin";
import Dashboard from "./pages/Dashboard";
import MyProfile from "./pages/MyProfile";
import UserManagement from "./pages/UserManagement";
import PaymentsManagement from "./pages/PaymentsManagement";
import EmployeeManagement from "./pages/EmployeeManagement";
import UserDetails from "./pages/UserDetails";
import SupportManagement from "./pages/SupportManagement";
import RoleManagement from "./pages/RoleManagement";
import PermissionManagement from "./pages/PermissionManagement";
import ProtectedLayout from "./layouts/ProtectedLayout";

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

function App() {
  const [permissions, setPermissions] = useState([]);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  function ScrollToTop() {
    const { pathname } = useLocation();
    useEffect(() => window.scrollTo(0, 0), [pathname]);
    return null;
  }

  // Fetch current user + permissions
  const fetchCurrentUser = async () => {
    const token = Cookies.get("adminToken");
    if (!token) return setIsAuthenticated(false);

    try {
      const res = await axios.get(`${API_BASE_URL}/admin/me`, {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.data.status) {
        setPermissions(res.data.user.permissions || []);
        setIsAuthenticated(true);
        localStorage.setItem("user", JSON.stringify(res.data.user)); // optional minimal info
      } else {
        setIsAuthenticated(false);
      }
    } catch (err) {
      console.error(err);
      setIsAuthenticated(false);
    }
  };

  useEffect(() => {
    fetchCurrentUser();
  }, []);

  // Optional: refresh permissions every 5 min
  useEffect(() => {
    const interval = setInterval(fetchCurrentUser, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <PermissionContext.Provider value={{ permissions, setPermissions }}>
      <BrowserRouter>
        <ScrollToTop />

        <Routes>
          {/* Login */}
          <Route
            path="/"
            element={<AdminLogin setAuth={setIsAuthenticated} setPermissions={setPermissions} />}
          />

          {/* Protected Routes */}
          <Route element={<ProtectedLayout />}>
            <Route
              path="/dashboard"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <Dashboard />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/myprofile"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <MyProfile />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewUser">
                    <UserManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users/:userId"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewUser">
                    <UserDetails />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/payment"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewPayment">
                    <PaymentsManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/support"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewSupport">
                    <SupportManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/employee"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewEmployee">
                    <EmployeeManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/roles"
              element={
                isAuthenticated ? (
                  <ProtectedRoute adminOnly>
                    <RoleManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/permissions"
              element={
                isAuthenticated ? (
                  <ProtectedRoute adminOnly>
                    <PermissionManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />
          </Route>

          {/* 404 */}
          <Route path="*" element={<div>404 - Page not found</div>} />
        </Routes>
      </BrowserRouter>
    </PermissionContext.Provider>
  );
}

export default App;
